import{c as t,S as a,j as o,m as i}from"./chunks/framework.DvQr6YbT.js";const p=JSON.parse('{"title":"Best Practices","description":"","frontmatter":{},"headers":[],"relativePath":"guides/best-practices.md","filePath":"guides/best-practices.md","lastUpdated":1783497907000}'),s={name:"guides/best-practices.md"};function n(r,e,l,c,h,d){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to “Best Practices”">​</a></h1><p>Knowlery works best as a rhythm, not a tool you visit. This page collects the practices that keep a knowledge base healthy over months — each one grounded in how the system actually behaves.</p><h2 id="the-core-loop-capture-→-cook-→-ask" tabindex="-1">The core loop: capture → cook → ask <a class="header-anchor" href="#the-core-loop-capture-→-cook-→-ask" aria-label="Permalink to “The core loop: capture → cook → ask”">​</a></h2><p>Everything else supports this loop.</p><ol><li><strong>Capture without ceremony.</strong> Raw notes, meeting scraps, clipped articles, MCP <code>capture</code> calls from conversations — they all land as plain user notes (or in <code>inbox/</code>). Don&#39;t organize at capture time; organization is what <code>/cook</code> is for. A messy inbox is normal; a lossy one is not.</li><li><strong>Cook in sessions, not continuously.</strong> Run <code>/cook</code> when there&#39;s a batch of material worth compiling — after a project phase, a reading session, a week of captures. The staleness report (<code>knowlery stale</code>, or Knowledge health on the dashboard) tells you exactly what&#39;s waiting: stale pages first, then uncooked notes, most recent first.</li><li><strong>Ask against the compiled layer.</strong> <code>/ask</code> and <code>knowlery query</code> answer from compiled pages, with citations. If answers feel thin, that&#39;s a cook-debt signal, not a retrieval problem.</li></ol><h2 id="trust-the-abstention" tabindex="-1">Trust the abstention <a class="header-anchor" href="#trust-the-abstention" aria-label="Permalink to “Trust the abstention”">​</a></h2><p>When retrieval says <code>No confident matches</code>, believe it. The engine abstains by design when the question isn&#39;t sufficiently covered by any page — that is the answer &quot;your knowledge base doesn&#39;t know this yet&quot;, which is exactly what you want to hear when it&#39;s true.</p><ul><li>Don&#39;t rephrase the question five ways to force a hit; if it matters, cook the material that should answer it.</li><li>Agents should relay abstention verbatim rather than padding it with guesses — the built-in skills and MCP tool descriptions already say this, so an agent that hallucinates around an abstention is misconfigured, not misinformed.</li></ul><h2 id="keep-the-two-layer-boundary-clean" tabindex="-1">Keep the two-layer boundary clean <a class="header-anchor" href="#keep-the-two-layer-boundary-clean" aria-label="Permalink to “Keep the two-layer boundary clean”">​</a></h2><p>The single most important structural rule: <strong>user notes are yours; the four compiled directories are the agent&#39;s.</strong></p><ul><li>Never hand-write pages into <code>entities/</code>, <code>concepts/</code>, <code>comparisons/</code>, <code>queries/</code> in bulk. Edit compiled pages when they&#39;re wrong, but creation should flow through <code>/cook</code>, which keeps <code>sources</code> citations and <code>SCHEMA.md</code> taxonomy consistent.</li><li>Never let an agent restructure your own notes. The built-in rules already enforce this; keep it that way when writing custom rules.</li><li><code>Library/</code> (installed bundles) is read-only reference material. When you want to own a bundle page, <strong>fork it</strong> into your own directories — don&#39;t edit it in place, or updates will refuse to overwrite your changes (by design).</li></ul><h2 id="citations-are-the-fabric" tabindex="-1">Citations are the fabric <a class="header-anchor" href="#citations-are-the-fabric" aria-label="Permalink to “Citations are the fabric”">​</a></h2><p>Compiled pages cite their sources with <code>sources:</code> frontmatter and wikilinks. This is not decoration — it is what makes the whole system mechanical:</p><ul><li>Staleness detection compares source mtimes against page mtimes; a page without citations can never be flagged stale.</li><li>Retrieval credits a compiled page when a raw note it cites matches the question — cross-language questions reach compiled answers through this.</li><li><code>/challenge</code> and Freshness Review walk citations to check claims.</li></ul><p>If you ever accept an agent-written page without citations, you&#39;ve created a page the machinery can&#39;t see. The &quot;Citation required&quot; rule exists for this.</p><h2 id="run-health-after-anything-bulky" tabindex="-1">Run health after anything bulky <a class="header-anchor" href="#run-health-after-anything-bulky" aria-label="Permalink to “Run health after anything bulky”">​</a></h2><p><code>knowlery health</code> (or Settings → Diagnostics) after imports, migrations, platform switches, or big agent sessions. It&#39;s cheap, it&#39;s read-only, and it catches the boring failures — missing skills, broken config, absent dirs — before they turn into confusing agent behavior. <code>knowlery sync</code> fixes what health reports; it&#39;s idempotent and write-on-change, so running it &quot;just in case&quot; costs nothing.</p><h2 id="schema-discipline-lightly-held" tabindex="-1">Schema discipline, lightly held <a class="header-anchor" href="#schema-discipline-lightly-held" aria-label="Permalink to “Schema discipline, lightly held”">​</a></h2><p><code>SCHEMA.md</code> is a living convention file. Let <code>/cook</code> extend the tag and domain taxonomy as new material arrives — that&#39;s its job — but review the diff occasionally. Two smells worth acting on:</p><ul><li><strong>Synonym tags</strong> (<code>ml</code>, <code>machine-learning</code>) — merge them; retrieval treats tags as evidence and synonyms split that evidence.</li><li><strong>One-page domains</strong> — usually a sign cook was too eager; fold them into an adjacent domain.</li></ul><p><code>/audit</code> reports structural drift (orphans, broken links, frontmatter gaps) when you want a deeper pass.</p><h2 id="sharing-review-means-reading" tabindex="-1">Sharing: review means reading <a class="header-anchor" href="#sharing-review-means-reading" aria-label="Permalink to “Sharing: review means reading”">​</a></h2><p>The export review gate shows you every page and every source that would ship, with risk hints (emails, sensitive URLs, person pages, meeting-like notes). The practices that keep this honest:</p><ul><li><strong>Read the checklist, don&#39;t skim it.</strong> There is deliberately no approve-all flag. If an agent drives the review, it must present the full checklist verbatim before acting on your decisions — that conduct is written into the skill, so hold it to that.</li><li><strong>Prefer private distribution by default.</strong> A GitHub Release on a private repo with <code>gh</code>-authenticated installs covers most sharing; <code>--public</code> exists behind a second acknowledgment gate for a reason — a public release is permanent (assume anything published publicly is downloaded the moment it goes up).</li><li><strong>Version deliberately.</strong> Subscribers see your version numbers; bump patch for corrections, minor for new pages. The update pipeline refuses to downgrade and refuses to overwrite local modifications — work with that grain, not against it.</li></ul><h2 id="multiple-kbs-split-by-audience-not-by-topic" tabindex="-1">Multiple KBs: split by audience, not by topic <a class="header-anchor" href="#multiple-kbs-split-by-audience-not-by-topic" aria-label="Permalink to “Multiple KBs: split by audience, not by topic”">​</a></h2><p>Registry names (<code>kb add</code>) are cheap, but knowledge bases are not free — each is a separate retrieval scope, cook scope, and sharing scope. A good split is by <em>who may see it</em> (work / personal / a shared team KB), because that boundary also decides export scope and remote exposure. Topics within one audience usually belong in one KB, organized by domains — federated query (<code>--kb &#39;*&#39;</code>) covers the &quot;where did I write this&quot; case across them.</p><h2 id="agents-give-them-the-front-door" tabindex="-1">Agents: give them the front door <a class="header-anchor" href="#agents-give-them-the-front-door" aria-label="Permalink to “Agents: give them the front door”">​</a></h2><ul><li>Point agents at <code>KNOWLEDGE.md</code> first; it&#39;s written for them.</li><li>Prefer the deterministic tools (<code>query</code>, <code>stale</code>, MCP tools) over letting an agent grep the vault — the engine&#39;s scoring, CJK handling, and abstention are all things ad-hoc grep lacks.</li><li>For MCP write tools, the conduct is: writes act on <em>your words</em>, never on agent initiative. An agent that captures silently or inits directories without restating the path is out of contract — the tool descriptions say so, and you should too.</li><li>Keep vaults in version control (or at least backups). Every Knowlery operation is designed to be non-destructive, but agents are agents.</li></ul><h2 id="what-not-to-do" tabindex="-1">What not to do <a class="header-anchor" href="#what-not-to-do" aria-label="Permalink to “What not to do”">​</a></h2><ul><li>Don&#39;t cache retrieval results or build parallel indexes — every query is a live scan by design; there is nothing to invalidate and no index to drift.</li><li>Don&#39;t hand-edit <code>.knowlery/</code> state files (<code>bundles.json</code>, <code>export-scope.json</code>, the registry) unless something is broken; they&#39;re contracts between shells.</li><li>Don&#39;t run an old CLI against a workspace a newer version has synced — the downgrade guard will refuse, and the fix is <code>npm i -g knowlery@latest</code>, not forcing past it.</li><li>Don&#39;t publish a bundle to a public repo &quot;to test&quot; — test with a private repo or a local zip; public is permanent.</li></ul>',30)])])}const g=t(s,[["render",n]]);export{p as __pageData,g as default};
